def write_files():
    for name, content in FILES.items():
        path = Path(name)
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")

def main():
    p = argparse.ArgumentParser(description="Bootstrap VeraFlow v11c Qualified End")
    p.add_argument("--run", action="store_true")
    p.add_argument("--log", default=None)
    p.add_argument("--json-summary", default=None)
    p.add_argument("--generate-ebnf", action="store_true")
    p.add_argument("--no-console", action="store_true")
    args = p.parse_args()
    write_files()
    print("[OK] VeraFlow v11c qualified-end files written.")

    if args.generate_ebnf:
        subprocess.run([sys.executable, "tools/lark_to_ebnf.py"], check=True)

    if args.run:
        cmd = [sys.executable, "run_modular_tests.py"]
        if args.log: cmd += ["--log", args.log]
        if args.json_summary: cmd += ["--json-summary", args.json_summary]
        if args.no_console: cmd.append("--no-console")
        raise SystemExit(subprocess.run(cmd, text=True).returncode)

if __name__ == "__main__":
    main()
